                    M(x + 0.4, z - 3.6);
                    C(x + 1.3, z - 3.7, x + 1.5, z - 2.6, x + 0.9, z - 2.1);
                    S();
                    M(x - 0.6, z - 0.9);
                    Qk(x + 0.1, z - 0.6, x + 0.55, z - 1.0);
